function getDebtLoanBalls(){return Math.floor(DEBT_UNIT_YEN/YEN_PER_BALL)}function getDebtRepayBalls(){return Math.floor(DEBT_REPAY_UNIT_YEN/YEN_PER_BALL)}function takeLoan(){const t=getDebtLoanBalls();state.debt+=t,state.balls+=t,state.totalInvest+=t,state.lastDebtTime===0&&(state.lastDebtTime=Date.now()),state.debtStartTime===0&&(state.debtStartTime=Date.now())}function processDebtInterest(){if(state.debt<=0)return;const t=Date.now();state.lastDebtTime===0&&(state.lastDebtTime=t);const e=t-state.lastDebtTime;if(e>=DEBT_INTERVAL_MS){const s=Math.floor(e/DEBT_INTERVAL_MS),a=state.debt;state.debt=state.debt*Math.pow(1+DEBT_INTEREST_RATE,s),state.lastInterest=state.debt-a,state.accumulatedInterest+=state.debt-a,state.lastDebtTime=t-e%DEBT_INTERVAL_MS}}function repayDebt(){if(state.debt<=0)return;const t=Math.ceil(state.debt);state.balls>=t?(state.balls-=t,state.debt=0,state.lastDebtTime=0,state.debtStartTime=0,state.lastInterest=0,state.accumulatedInterest=0):(state.debt-=state.balls,state.balls=0),saveGame()}function repayPartial(){if(state.debt<=0)return;const t=getDebtRepayBalls();if(!(state.balls<t)){if(state.debt<=t){repayDebt();return}state.balls-=t,state.debt-=t,saveGame()}}
